var n = 320 + R.int(180);
var flakes = [];
for (var i = 0; i < n; i++) {
  flakes.push({
    x: R.dec(),
    y: R.dec(),
    z: 0.08 + R.dec() * 0.92,
    vx: (R.dec() - 0.5) * 0.012,
    tw: R.dec() * Math.PI * 2
  });
}
var trees = [];
for (var t = 0; t < 72; t++) {
  trees.push({
    side: R.dec() < 0.5 ? -1 : 1,
    lane: R.dec(),
    y: -0.35 + R.dec() * 1.55,
    h: 0.22 + R.dec() * 0.30
  });
}
return Object.assign({}, state, { flakes: flakes, trees: trees, runT: 0 });
